127	const startProjectSchedulerLoop = (scheduler: ProjectScheduler): void => {
128	  if (scheduler.loopStarted) return;
129	  scheduler.loopStarted = true;
130	  void (async () => {
131	    for (;;) {
132	      await runBackendEffect(Queue.take(scheduler.wakeQueue));
133	      try {
134	        await runBackendEffect(Effect.retry(fromPromise(() => drainProjectScheduler(scheduler.projectPath)), schedulerRetryPolicy));
135	      } catch (error) {
136	        await logError("codex:scheduler", "queue drain failed", error, { projectPath: scheduler.projectPath });
137	      }
138	    }
139	  })().catch((error) => {
140	    scheduler.loopStarted = false;
141	    void logError("codex:scheduler", "scheduler loop stopped", error, { projectPath: scheduler.projectPath });
142	  });
143	};
