145	const getProjectScheduler = async (projectPath: string): Promise<ProjectScheduler> => {
146	  const resolvedProjectPath = pathResolve(projectPath);
147	  const existing = projectSchedulers.get(resolvedProjectPath);
148	  if (existing) return existing;
149	
150	  const created = (async (): Promise<ProjectScheduler> => {
151	    const wakeQueue = await runBackendEffect(Queue.unbounded<void>());
152	    const scheduler: ProjectScheduler = {
153	      projectPath: resolvedProjectPath,
154	      wakeQueue,
155	      loopStarted: false
156	    };
157	    startProjectSchedulerLoop(scheduler);
158	    return scheduler;
159	  })();
160	  projectSchedulers.set(resolvedProjectPath, created);
161	  return created;
162	};
