176	const drainProjectScheduler = async (projectPath: string): Promise<void> => {
177	  const config = await readProjectConfig(projectPath);
178	  const concurrency = Math.max(1, config.settings.agentConcurrency);
179	
180	  while (activeImplementationRunCountForProject(projectPath) < concurrency) {
181	    const next = (await listQueuedReadyTickets(projectPath)).find((ticket) => {
182	      const runId = ticket.lastRunId;
183	      return Boolean(runId && !activeRuns.has(runId) && !startingRuns.has(runId));
184	    });
185	    if (!next?.lastRunId) return;
186	
187	    const runId = next.lastRunId;
188	    const intent =
189	      queuedRunIntents.get(runId) ??
190	      ({
191	        input: { projectPath, ticketId: next.id },
192	        resume: Boolean(next.codexThreadId),
193	        dependencies: {}
194	      } satisfies QueuedRunIntent);
195	    queuedRunIntents.set(runId, intent);
196	    startingRuns.set(runId, { projectPath, ticketId: next.id });
197	    void startQueuedRunNow(intent.input, intent.resume, runId, intent.dependencies).catch((error) =>
198	      logError("codex:run", "queued run failed outside stream", error, { projectPath, ticketId: next.id, runId })
199	    );
200	  }
