1238	const extractMarkdownSection = (markdown: string, heading: string): string | null => {
1239	  const pattern = new RegExp(`^## ${heading.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\s*$`, "m");
1240	  const match = pattern.exec(markdown);
1241	  if (!match) return null;
1242	  const start = match.index + match[0].length;
1243	  const rest = markdown.slice(start);
1244	  const nextHeading = rest.search(/\n##\s+/);
1245	  return (nextHeading >= 0 ? rest.slice(0, nextHeading) : rest).trim();
1246	};
