2404	export const reconcileTicketQueueState = async (
2405	  projectPath: string,
2406	  ticketId: string,
2407	  dependencies: CodexRunDependencies = {}
2408	): Promise<TicketRecord> => {
2409	  const resolvedProjectPath = pathResolve(projectPath);
2410	  const ticket = await readTicket(resolvedProjectPath, ticketId);
2411	
2412	  if (ticket.frontMatter.status === RELAY_READY_STATUS) {
2413	    if (ticket.frontMatter.runStatus === "queued" && ticket.frontMatter.lastRunId) {
2414	      if (!queuedRunIntents.has(ticket.frontMatter.lastRunId)) {
2415	        queuedRunIntents.set(ticket.frontMatter.lastRunId, {
2416	          input: { projectPath: resolvedProjectPath, ticketId },
2417	          resume: Boolean(ticket.frontMatter.codexThreadId),
2418	          dependencies
2419	        });
2420	      }
2421	      wakeProjectSchedulerSoon(resolvedProjectPath);
2422	      return ticket;
2423	    }
2424	    if (ticket.frontMatter.runStatus === "running" || ticket.frontMatter.runStatus === "drafting") return ticket;
2425	
2426	    const preflight = await preflightCodexRunInternal({ projectPath: resolvedProjectPath, ticketId });
2427	    if (!preflight.ok) {
2428	      throw new Error(preflight.errors.join(" "));
2429	    }
2430	    const runId = dependencies.createRunId?.() ?? newId("run");
2431	    queuedRunIntents.set(runId, {
2432	      input: { projectPath: resolvedProjectPath, ticketId },
2433	      resume: Boolean(ticket.frontMatter.codexThreadId),
2434	      dependencies
2435	    });
2436	    try {
2437	      const queued = await setTicketQueued(resolvedProjectPath, ticketId, runId);
2438	      wakeProjectSchedulerSoon(resolvedProjectPath);
2439	      return queued;
2440	    } catch (error) {
2441	      queuedRunIntents.delete(runId);
2442	      throw error;
2443	    }
2444	  }
2445	
2446	  if (ticket.frontMatter.runStatus === "queued" && ticket.frontMatter.lastRunId) {
2447	    queuedRunIntents.delete(ticket.frontMatter.lastRunId);
2448	    return clearQueuedTicket(resolvedProjectPath, ticketId, null, ticket.frontMatter.lastRunId);
2449	  }
2450	
2451	  return ticket;
2452	};
