2454	export const cancelCodexRun = async (runId: string): Promise<void> => {
2455	  const queued = queuedRunIntents.get(runId);
2456	  if (queued) {
2457	    queuedRunIntents.delete(runId);
2458	    startingRuns.delete(runId);
2459	    const active = activeRuns.get(runId);
2460	    if (active) {
2461	      active.abortController.abort();
2462	      await updateTicketRunState(active.projectPath, active.ticketId, { runStatus: "cancelled" });
2463	      return;
2464	    }
2465	    const projectPath = pathResolve(queued.input.projectPath);
2466	    const targetStatus = (await readProjectConfig(projectPath)).columns.some((column) => column.id === RELAY_TODO_STATUS)
2467	      ? RELAY_TODO_STATUS
2468	      : null;
2469	    await clearQueuedTicket(projectPath, queued.input.ticketId, targetStatus, runId);
2470	    wakeProjectSchedulerSoon(projectPath);
2471	    return;
2472	  }
2473	
2474	  const run = activeRuns.get(runId);
2475	  if (!run) return;
2476	  run.abortController.abort();
2477	  await updateTicketRunState(run.projectPath, run.ticketId, { runStatus: "cancelled" });
2478	};
